={{
(() => {
  const start = new Date($json["Start Date"]);
  const target = new Date($json["Target Date"]);
  const today = new Date();

  const totalDays = Math.floor((target - start) / (1000 * 60 * 60 * 24));
  const daysPassed = Math.floor((today - start) / (1000 * 60 * 60 * 24));

  if (!totalDays || totalDays <= 0) return 0;

  return ($json["Goal Amount"] / totalDays) * Math.max(0, daysPassed);
})()
}}

